code = """import json
import pandas as pd

# Get the stored results
children_books_data = var_functions.query_db_18
file_path = var_functions.query_db_20

# Load the 2020+ reviews data from file
with open(file_path, 'r') as f:
    reviews_2020 = json.load(f)

# Create DataFrames
df_children = pd.DataFrame(children_books_data)
df_reviews = pd.DataFrame(reviews_2020)

# Convert rating to float
df_reviews['rating'] = df_reviews['rating'].astype(float)

# Extract book_id from purchase_id (format: purchaseid_8 -> bookid_8)
df_reviews['book_num'] = df_reviews['purchase_id'].str.replace('purchaseid_', '')
df_reviews['book_id'] = 'bookid_' + df_reviews['book_num']

# Merge children books with 2020+ reviews
merged = df_children.merge(df_reviews, on='book_id', how='inner')

# Calculate average rating per book
avg_ratings = merged.groupby(['book_id', 'title']).agg(
    avg_rating=('rating', 'mean'),
    review_count=('rating', 'count')
).reset_index()

# Filter books with average rating >= 4.5
high_rated = avg_ratings[avg_ratings['avg_rating'] >= 4.5]

# Sort by rating descending, then by review count
high_rated_sorted = high_rated.sort_values(['avg_rating', 'review_count'], ascending=[False, False])

result = high_rated_sorted.to_dict('records')

print('__RESULT__:')
print(json.dumps(result))"""

